// QueryBusiness queries the business edge of a HubWorker.
func (c *HubWorkerClient) QueryBusiness(_m *HubWorker) *HubBusinessQuery {
	query := (&HubBusinessClient{config: c.config}).Query()
	query.path = func(context.Context) (fromV *sql.Selector, _ error) {
		id := _m.ID
		step := sqlgraph.NewStep(
			sqlgraph.From(hubworker.Table, hubworker.FieldID, id),
			sqlgraph.To(hubbusiness.Table, hubbusiness.FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, hubworker.BusinessTable, hubworker.BusinessColumn),
		)
		schemaConfig := _m.schemaConfig
		step.To.Schema = schemaConfig.HubBusiness
		step.Edge.Schema = schemaConfig.HubWorker
		fromV = sqlgraph.Neighbors(_m.driver.Dialect(), step)
		return fromV, nil
	}
	return query
}

// Hooks returns the client hooks.
func (c *HubWorkerClient) Hooks() []Hook {
	return c.hooks.HubWorker
}

// Interceptors returns the client interceptors.
func (c *HubWorkerClient) Interceptors() []Interceptor {
	return c.inters.HubWorker
}

func (c *HubWorkerClient) mutate(ctx context.Context, m *HubWorkerMutation) (Value, error) {
	switch m.Op() {
	case OpCreate:
		return (&HubWorkerCreate{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpUpdate:
		return (&HubWorkerUpdate{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpUpdateOne:
		return (&HubWorkerUpdateOne{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpDelete, OpDeleteOne:
		return (&HubWorkerDelete{config: c.config, hooks: c.Hooks(), mutation: m}).Exec(ctx)
	default:
		return nil, fmt.Errorf("ent: unknown HubWorker mutation op: %q", m.Op())
	}
}

