type (
	hooks struct {
		HubBusiness, HubCommunityReview, HubCommunityWorker, HubEvent, HubLock,
		HubPlaybook, HubWorker []ent.Hook
	}
	inters struct {
		HubBusiness, HubCommunityReview, HubCommunityWorker, HubEvent, HubLock,
		HubPlaybook, HubWorker []ent.Interceptor
	}
)

